        return (char)0xFF;
    }

    // Check for negative offsets or indices
    if (text_offset < 0 || char_index < 0) {
        return (char)0xFF;
    }

    // Check if text offset is beyond document bounds
    if (text_offset >= doc_size) {
        return (char)0xFF;
    }

    // Check if character index would exceed document bounds
    if (char_index >= (doc_size - text_offset)) {
        return (char)0xFF;
    }

    // Return the character at the calculated position
    return doc_data[text_offset + char_index];
}
